      "sourceText": "Ich habe Kopfschmerzen.",
      "modelAnswer": "J'ai mal à la tête.",
      "alternatives": [
        "Je souffre de maux de tête."
      ],
      "keyPoints": [
        "A1 vocabulary: Kopfschmerzen = mal à la tête",
        "Present tense: avoir (j'ai)",
        "Simple expression of physical state"
      ]
    },
    {
      "sourceText": "Ich fühle mich krank.",
      "modelAnswer": "Je me sens malade.",
      "alternatives": [
        "J'ai la grippe."
      ],
      "keyPoints": [
        "A1 vocabulary: krank = malade, fühlen = sentir",
        "Present tense: je me sens",
        "Basic self-reference with feeling"
      ]
    },
    {
      "sourceText": "Das Wasser ist kalt.",
      "modelAnswer": "L'eau est froide.",
      "alternatives": [
        "L'eau est très froide."
      ],
      "keyPoints": [
        "A1 vocabulary: Wasser = eau, kalt = froid",
        "Present tense: être (est)",
        "Simple description of temperature"
      ]
    },
    {
      "sourceText": "Ich trinke viel Wasser.",
      "modelAnswer": "Je bois beaucoup d'eau.",
      "alternatives": [
        "J'ai soif."
      ],
      "keyPoints": [
        "A1 vocabulary: trinken = boire, viel = beaucoup, Wasser = eau",
        "Present tense: je bois",
        "Basic daily habit with quantity"
      ]
    },
    {
      "sourceText": "Der Arzt hilft mir.",
      "modelAnswer": "Le médecin m'aide.",
      "alternatives": [
        "Il me soigne."
      ],
      "keyPoints": [
        "A1 vocabulary: Arzt = médecin, helfen = aider",
        "Present tense: il aide",
        "Simple subject-object relationship"
      ]
    }
  ]
